warp = 0;;
zoom = 1;;
tic = min(time-tin,.1);;
tin = time;;
vol = (bass_att + treb_att + mid_att)*.333333;;
ra = 1/tic*.25;;
treb_avg = tic*(treb_avg*(1/tic - ra) + ra*treb);;
mid_avg = tic*(mid_avg*(1/tic - ra) + ra*mid);;
bass_avg = tic*(bass_avg*(1/tic - ra) + ra*bass);;
vav = tic*(vav*(1/tic - ra) + ra*(bass+treb+mid)*.33333);;
tt = tt + tic*treb;;
mt = mt + tic*mid;;
bt = bt + tic*bass;;
vt = vt + tic*vav;;
sp = abs(vav - slide)*.5;;
slide = if(((slide) > (vav)),slide-tic*sp,slide+tic*sp) + ((slide) == (0))*vav*.2;;
q1 = bt - (mt + tt)*.3; // rotation;
q2 = pow(1 + vav,1) - 1; // zoom strength;
q3 = .6 + slide*.2; // triangle radius;
q4 = 1/q3*.64; // triangle tex_zoom;
q5 = q1 + 4.7124 + .7851; // triangle tex_ang;
sw = 1-sw;;
q6 = -sw; // triangle additive value;
monitor = slide;
